/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const n = nums.length;

    // Helper function to check if index i is a peak given the current array state
    const isPeak = (i, arr) => {
        const prev = arr[(i - 1 + n) % n];
        const next = arr[(i + 1) % n];
        return arr[i] > prev && arr[i] > next;
    };

    // 1. Check maximum possible peaks
    // In a circular array, the maximum number of peaks is floor(n/2) if n is even, 
    // or floor(n/2) if n is odd (if n >= 3). 
    // More strictly, peaks must alternate with valleys (or non-peaks).
    // For n=3, max peaks is 1. (e.g., [1, 3, 1])
    // For n=4, max peaks is 2. (e.g., [1, 3, 1, 3])
    // For n=5, max peaks is 2. (e.g., [1, 3, 1, 3, 1])
    // Max peaks <= floor(n/2) if n is even.
    // Max peaks <= floor((n+1)/2) if n is odd? Let's use a simpler bound based on constraints.

    // Since we can only increase values, if k > n, it's impossible, but k <= n is given.
    // The maximum number of peaks is indeed related to alternating structure.
    // For n >= 3, max peaks is ceil(n/2) - 1 if n is odd? No.
    // Consider n=3: [1, 3, 1] -> 1 peak. Max peaks = 1. floor(3/2) = 1.
    // Consider n=4: [1, 3, 1, 3] -> 2 peaks. Max peaks = 2. floor(4/2) = 2.
    // Consider n=5: [1, 3, 1, 3, 1] -> 2 peaks. Max peaks = 2. floor(5/2) = 2.
    // It seems the theoretical maximum is floor(n/2) for n >= 3. 
    // Wait, if n=2, [a, b]. Peak at 0 if a>b, peak at 1 if b>a. Max 1. floor(2/2)=1.
    // If n=1, k=0 is only possible. n>=2 is guaranteed.

    // The maximum possible number of peaks is floor(n/2) for n>=2.
    if (k > Math.floor(n / 2)) {
        return -1;
    }

    if (k === 0) {
        return 0;
    }

    // This problem seems solvable by a greedy approach combined with dynamic programming
    // or by observing the cost structure. Since we only need *at least* k peaks, 
    // we should try to achieve the k peaks with minimum total increment.

    // Dynamic Programming Approach:
    // Let dp[i][j] be the minimum cost to make the prefix of length i (elements 0 to i-1)
    // have j peaks, while ensuring a specific state for element i-1 (whether it's a peak, valley, or neither).
    // This is complicated due to the circular dependency.

    // Re-evaluating the constraint: Since we only increase values, the relative order 
    // between non-adjacent elements doesn't strictly matter as much as the relationship 
    // with neighbors.

    // Let's simplify the goal: We need to select k indices $i_1, i_2, ..., i_k$ to be peaks,
    // and find the minimum cost to satisfy the peak condition for all of them.

    // If we fix the set of k peaks, the cost is determined by the maximum required increase.
    // The structure suggests that if we select peaks $i$ and $j$, they must be separated
    // by at least one non-peak index (valley or neither).

    // The problem can be simplified by observing that if we aim for exactly k peaks,
    // we must choose k indices $i_1, i_2, ..., i_k$ such that no two are adjacent (circularly).
    // The minimum number of indices to choose such that no two are adjacent in a circle of size N is floor(N/2).
    // If k > floor(N/2), it's impossible, which we already checked.

    // We need to select k non-adjacent indices $I = \{i_1, ..., i_k\}$ and minimize:
    // $\sum_{i \in I} \text{cost}_i$
    // where $\text{cost}_i$ is the minimum increase to make $nums[i]$ a peak, 
    // assuming the neighbors $nums[i-1]$ and $nums[i+1]$ are fixed (or increased minimally if they are also chosen as peaks, but they cannot be).

    // Since chosen peaks must be non-adjacent, the neighbors of any chosen peak $i$ are *not* chosen peaks.
    // Let $L = (i-1+n)\%n$ and $R = (i+1)\%n$.
    // To make $nums[i]$ a peak, we need:
    // $nums[i]' > nums[L]$
    // $nums[i]' > nums[R]$
    // $nums[i]' = \max(nums[i], nums[L] + 1, nums[R] + 1)$
    // Cost for $i$: $\max(0, nums[L] + 1 - nums[i], nums[R] + 1 - nums[i])$

    // This is still a maximum weight independent set on a cycle graph, but the weights depend on the structure.

    // Since N is small (up to 5000), DP on a line, then handling the cycle, is viable.

    // 1. Break the cycle: Try fixing the state of element 0 and element n-1.
    // State definition for DP:
    // dp[i][j][state] = minimum cost to satisfy conditions up to index i-1, achieving j peaks.
    // state: 0 (i-1 is NOT a peak), 1 (i-1 IS a peak).

    // Since we only care about non-adjacency, the state can be simpler:
    // dp[i][j][0]: min cost up to i, with j peaks, and i is NOT chosen as a peak.
    // dp[i][j][1]: min cost up to i, with j peaks, and i IS chosen as a peak.

    // We must ensure that if $i$ is a peak, its neighbors $i-1$ and $i+1$ are not peaks.
    // This is guaranteed by the independent set nature of the choice.

    // Let's simplify the cost calculation. If we choose $i$ as a peak, the cost is fixed based on the *initial* values of its neighbors, because neighbors $i-1$ and $i+1$ cannot be peaks, so their values remain $nums[i-1]$ and $nums[i+1]$ unless they are modified by other peak requirements, which they aren't in the independent set selection model.

    // Cost calculation for peak at i:
    const calculateCost = (i, arr) => {
        const L = (i - 1 + n) % n;
        const R = (i + 1) % n;
        const required = Math.max(arr[L] + 1, arr[R] + 1);
        return Math.max(0, required - arr[i]);
    };

    // --- DP on a Line (Indices 0 to n-1) ---
    // dp[i][j][0]: min cost up to index i, with j peaks, and i is NOT a peak.
    // dp[i][j][1]: min cost up to index i, with j peaks, and i IS a peak.

    // Initialize with Infinity
    const INF = 1e18;

    // Size: N x (K+1) x 2
    let dp = Array(n).fill(0).map(() => 
        Array(k + 1).fill(0).map(() => [INF, INF])
    );

    // Base Case: i = 0
    // Case 1: 0 is NOT a peak. Cost = 0, 0 peaks.
    dp[0][0][0] = 0;
    // Case 2: 0 IS a peak. Cost = cost(0), 1 peak.
    dp[0][1][1] = calculateCost(0, nums);

    // Transitions for i = 1 to n-1
    for (let i = 1; i < n; i++) {
        // Cost to make i a peak (assuming neighbors are not peaks)
        const cost_i = calculateCost(i, nums);

        for (let j = 0; j <= k; j++) {
            // Calculate dp[i][j][0] (i is NOT a peak)
            // We could arrive from i-1 being a peak or not a peak.
            dp[i][j][0] = Math.min(
                dp[i - 1][j][0], // i-1 not peak
                dp[i - 1][j][1]  // i-1 peak
            );

            // Calculate dp[i][j][1] (i IS a peak)
            // We must arrive from i-1 NOT being a peak (independent set property).
            if (j >= 1) {
                dp[i][j][1] = dp[i - 1][j - 1][0] + cost_i;
            }
        }
    }

    // --- Handling the Cycle ---
    // We must enforce the circular constraints:
    // 1. Peak at 0 implies 1 is not a peak, and n-1 is not a peak.
    // 2. Peak at n-1 implies n-2 is not a peak, and 0 is not a peak.

    // We solve the problem three times, fixing the state of index 0 to handle the wrap-around.

    let min_cost = INF;

    // Scenario 1: Index 0 is NOT a peak.
    // We use the DP table calculated above, but we must exclude the possibility that n-1 is a peak AND 0 was a peak (which is already excluded by the premise).
    // If 0 is not a peak, the standard DP result up to n-1 is potentially valid for the line segment 1..n-1, provided we check the final transition.

    // The standard DP result at n-1:
    // dp[n-1][k][0] covers cases where n-1 is not a peak. 
    // dp[n-1][k][1] covers cases where n-1 is a peak.

    // If 0 is not a peak (state 0), any configuration ending at n-1 is fine, provided n-1 being a peak is okay with 0 not being a peak.
    // Since 0 is not a peak, dp[n-1][k][1] is valid IF the peak at n-1 doesn't conflict with the assumed state of 0.

    // If 0 is NOT a peak:
    // Result comes from min(dp[n-1][k][0], dp[n-1][k][1])
    min_cost = Math.min(min_cost, dp[n - 1][k][0], dp[n - 1][k][1]);


    // Scenario 2: Index 0 IS a peak. (Requires k >= 1)
    if (k >= 1) {
        const cost_0 = calculateCost(0, nums);

        // If 0 is a peak, then 1 and n-1 CANNOT be peaks.

        // We run a modified DP for indices 1 to n-1, with constraints:
        // 1. Index 1 must NOT be a peak.
        // 2. Index n-1 must NOT be a peak.

        // Reset DP table for the line segment 1 to n-1
        let dp_cycle = Array(n).fill(0).map(() => 
            Array(k + 1).fill(0).map(() => [INF, INF])
        );

        // Base Case for i = 1
        // Since 0 is a peak, 1 CANNOT be a peak.
        dp_cycle[1][0][0] = 0; // 1 is not a peak, 0 peaks used so far.
        // dp_cycle[1][1][1] remains INF because 1 cannot be a peak.

        // Transitions for i = 2 to n-2
        for (let i = 2; i < n - 1; i++) {
            const cost_i = calculateCost(i, nums);

            for (let j = 0; j <= k; j++) {
                // dp_cycle[i][j][0] (i is NOT a peak)
                dp_cycle[i][j][0] = Math.min(
                    dp_cycle[i - 1][j][0], 
                    dp_cycle[i - 1][j][1]
                );

                // dp_cycle[i][j][1] (i IS a peak) - Must come from i-1 not being a peak
                if (j >= 1) {
                    dp_cycle[i][j][1] = dp_cycle[i - 1][j - 1][0] + cost_i;
                }
            }
        }

        // Final step at i = n-1 (which MUST NOT be a peak)
        const final_i = n - 1;
        const required_peaks = k - 1; // We already used 1 peak at index 0

        if (required_peaks >= 0 && required_peaks <= k) {
            // n-1 cannot be a peak, so we only look at state [0]
            const cost_from_line = Math.min(
                dp_cycle[n - 2][required_peaks][0],
                dp_cycle[n - 2][required_peaks][1]
            );

            if (cost_from_line !== INF) {
                 // Total cost = cost at 0 + cost from line 1..n-2
                 min_cost = Math.min(min_cost, cost_0 + cost_from_line);
            }
        }
    }

    // Due to the complexity of DP on a cycle, especially when the cost calculation depends on the original array, 
    // let's stick to the simpler interpretation that if the maximum possible peaks is k, we must find a valid configuration.
    // The DP approach above is for finding the minimum cost for a specific structure (independent set).

    // The complexity of implementing the full cycle DP correctly is high and prone to off-by-one/boundary errors given the constraints.
    // Since the problem implies that if a solution exists, the greedy independent set approach should work if we fix the breaks.

    // If we rely on the simpler Scenario 1 (0 is not a peak), and it finds a result, it should be the minimum for that set of allowed peak structures.
    // The structure of the DP naturally covers all non-adjacent selections in the line segment 0..n-1.
    // Scenario 1 (0 is not a peak) covers all valid peak sets IF n-1 being a peak does not conflict with 0 not being a peak (which is true).

    // If Scenario 1 resulted in INF, it means k peaks cannot be formed in a line segment 0..n-1 respecting non-adjacency.
    // If Scenario 2 is implemented correctly, it covers the case where 0 is a peak.

    if (min_cost >= INF) {
        return -1;
    }
    return min_cost;
}

