#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

typedef long long ll;

// Define a large value for infinity
const ll INF = 1e18;

/**
 * Helper function to calculate the cost required to make index i a peak
 * based on its current neighbors in the original array nums.
 */
ll calculateCost(int i, int n, const std::vector<long long>& arr) {
    int L = (i - 1 + n) % n;
    int R = (i + 1) % n;

    // Required value for nums[i] must be strictly greater than both neighbors
    long long required = std::max(arr[L] + 1, arr[R] + 1);

    return std::max(0LL, required - arr[i]);
}

long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();

    if (k == 0) {
        return 0;
    }

    // Theoretical maximum number of non-adjacent peaks in a circle of size n is floor(n/2).
    if (k > n / 2) {
        return -1;
    }

    if (n < 2) {
        // Should not happen based on constraints (n >= 2)
        return -1;
    }

    ll min_cost = INF;

    // --- Strategy: Use DP on a line segment, fixing the state of index 0 to handle the cycle ---

    // Case 1: Index 0 is NOT a peak.
    // We run DP on the line segment [0, n-1] assuming no wrap-around conflict is triggered by 0.

    // dp[i][j][0]: min cost up to index i, with j peaks, and i is NOT chosen as a peak.
    // dp[i][j][1]: min cost up to index i, with j peaks, and i IS chosen as a peak.

    // Size: N x (K+1) x 2
    std::vector<std::vector<std::vector<ll>>> dp1(n, std::vector<std::vector<ll>>(k + 1, std::vector<ll>(2, INF)));

    // Base Case: i = 0
    // 0 is NOT a peak
    dp1[0][0][0] = 0;
    // 0 IS a peak
    dp1[0][1][1] = calculateCost(0, n, nums);

    // Transitions for i = 1 to n-1
    for (int i = 1; i < n; i++) {
        ll cost_i = calculateCost(i, n, nums);

        for (int j = 0; j <= k; j++) {
            // dp1[i][j][0] (i is NOT a peak)
            // Can arrive from i-1 being a peak or not a peak.
            dp1[i][j][0] = std::min(
                dp1[i - 1][j][0], 
                dp1[i - 1][j][1]
            );

            // dp1[i][j][1] (i IS a peak) - Must come from i-1 NOT being a peak
            if (j >= 1) {
                dp1[i][j][1] = dp1[i - 1][j - 1][0] + cost_i;
            }
        }
    }

    // Result from Case 1 (0 is NOT a peak):
    // The standard DP result covers all non-adjacent sets where 0 is not in the set.
    // We must check if n-1 being a peak conflicts with 0 not being a peak. Since 0 is not a peak, it doesn't conflict.
    min_cost = std::min(min_cost, dp1[n - 1][k][0]);
    min_cost = std::min(min_cost, dp1[n - 1][k][1]);


    // Case 2: Index 0 IS a peak. (Requires k >= 1)
    if (k >= 1) {
        ll cost_0 = calculateCost(0, n, nums);

        // If 0 is a peak, then 1 and n-1 CANNOT be peaks.

        // We run DP on the line segment [1, n-2] subject to constraints.

        // dp2[i][j][0]: min cost up to index i, with j peaks (excluding 0), and i is NOT chosen.
        // dp2[i][j][1]: min cost up to index i, with j peaks (excluding 0), and i IS chosen.

        // Size: N x (K) x 2. We only use indices 1 to N-2 effectively.
        std::vector<std::vector<std::vector<ll>>> dp2(n, std::vector<std::vector<ll>>(k + 1, std::vector<ll>(2, INF)));

        // Base Case for i = 1
        // Since 0 is a peak, 1 CANNOT be a peak.
        dp2[1][0][0] = 0; 
        // dp2[1][j][1] remains INF

        // Transitions for i = 2 to n-2
        for (int i = 2; i < n - 1; i++) {
            ll cost_i = calculateCost(i, n, nums);

            for (int j = 0; j <= k; j++) {
                // dp2[i][j][0] (i is NOT a peak)
                dp2[i][j][0] = std::min(
                    dp2[i - 1][j][0], 
                    dp2[i - 1][j][1]
                );

                // dp2[i][j][1] (i IS a peak) - Must come from i-1 not being a peak
                if (j >= 1) {
                    dp2[i][j][1] = dp2[i - 1][j - 1][0] + cost_i;
                }
            }
        }

        // Final step at i = n-2. We need k-1 more peaks from [1, n-2].
